SELECT AVG(close_price) AS avg_close_price
FROM stock_prices
WHERE date LIKE '%2022%' AND ticker_id = (SELECT ticker_id FROM tickers WHERE ticker_symbol = 'GOOGL');

SELECT AVG(adj_close_price) AS average_adj_close
FROM stock_prices
WHERE ticker_id IN (
  SELECT DISTINCT ticker_id
  FROM trades
);

SELECT close_price 
FROM stock_prices
WHERE date = (
    SELECT date 
    FROM stock_prices 
    WHERE high_price = (
        SELECT MAX(high_price) 
        FROM stock_prices
    )
);

SELECT AVG(close_price) AS average_close_price
FROM stock_prices
WHERE date = (SELECT access_date FROM access_logs WHERE access_id = 0);
